DECLARE
    DAY_NUM NUMBER := 3;
    DAY_NAME VARCHAR2(20);
BEGIN
    CASE
        WHEN DAY_NUM = 1 THEN day_name := 'Monday';
        WHEN DAY_NUM = 2 THEN day_name := 'Tuesday';
        WHEN DAY_NUM = 3 THEN day_name := 'Wednesday';
        WHEN DAY_NUM = 4 THEN day_name := 'Thursday';
        WHEN DAY_NUM = 5 THEN day_name := 'Friday';
        WHEN DAY_NUM = 6 THEN day_name := 'Saturday';
        WHEN DAY_NUM = 7 THEN day_name := 'Sunday';
        ELSE DAY_NAME := 'Invalid Day';
    END CASE;

    DBMS_OUTPUT.PUT_LINE('The day is: ' || DAY_NAME);
END;

